insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('magere-kwark', 'Magere kwark', 54, 10, 4, 0.2, 0, 'dairy', false, null, null, false, '10 gram eiwit per 100 gram voor 54 kcal. De beste eiwit/calorie-verhouding in je hele lijst. Caseïne, dus langzaam verteerbaar.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('skyr', 'Skyr', 63, 11, 4, 0.2, 0, 'dairy', false, null, null, false, '11 gram eiwit per 100 gram — net boven kwark. IJslandse wrongel, dus net als kwark caseïnedominant en traag verteerbaar.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('huttenkase', 'Hüttenkäse', 95, 12, 3, 4, 0, 'dairy', false, null, null, false, '12 gram eiwit per 100 gram, iets vetter dan kwark (4 gram). De hartige optie in een verder zoete zuivellijst.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('griekse-yoghurt', 'Griekse yoghurt 0%', 59, 10, 4, 0, 0, 'dairy', false, null, null, false, '10 gram eiwit per 100 gram voor 59 kcal — vrijwel kwark. Alleen de 0%-variant; de volle versie verdrievoudigt de calorieën.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('kefir', 'Kefir naturel', 50, 3.4, 4, 2, 0, 'drink', false, null, null, false, '3,4 gram eiwit per 100 ml — een derde van kwark. Prima als drank of om kwark drinkbaar te maken, maar reken het niet mee als eiwitbron.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('halfvolle-melk', 'Halfvolle melk', 46, 3.5, 4.7, 1.5, 0, 'drink', false, null, null, false, 'Zelfde verhaal als kefir: 3,5 gram eiwit per 100 ml. Om 40 gram eiwit uit melk te halen moet je meer dan een liter drinken. Ingrediënt, geen eiwitbron.', 'seed', null)
insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('volkorenbrood', 'Volkorenbrood', 235, 9, 40, 3, 6, 'grain', false, null, 35, false, null, 'seed', null)
