insert into public.if_ingredients (slug, name, kcal_100g, protein_100g, carb_100g, fat_100g, fiber_100g, category, is_nut, nut_type, piece_grams, is_peanut_butter, rationale, source, external_id) values ('zwarte-peper', 'Zwarte peper', 255, 10, 64, 3, 25, 'other', false, null, null, false, null, 'seed', null)
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('b01', 'De kwarkbak', '400 g magere kwark met banaan, walnoten en kaneel.', array['BREAK_FAST']::text[], 'cold', 'portable', 'slow', true, 3, 'kwark', '40 gram eiwit voor 215 kcal — de beste eiwit/calorie-verhouding in je hele bibliotheek. De banaan levert koolhydraten voor je middag, de 20 gram walnoot is je dagelijkse omega-3-basis. Alles wat je hierboven kiest, wordt hieraan afgemeten.', '44 g eiwit voor 452 kcal — je referentie.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('b02', 'Kwark met blauwe bessen en amandel', '400 g magere kwark met blauwe bessen en amandelen.', array['BREAK_FAST']::text[], 'cold', 'portable', 'slow', true, 3, 'kwark', 'Bessen in plaats van banaan scheelt 50 kcal en levert meer vezels. Kies deze op rustdagen, waar je de koolhydraten van een banaan minder nodig hebt.', '44 g eiwit, 50 kcal lichter dan de kwarkbak.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('b03', 'Kwark-kefir smoothie', 'Kwark, kefir en banaan, geblend tot een drinkbare shake.', array['BREAK_FAST']::text[], 'cold', 'on_the_go', 'fast', true, 4, 'smoothie', 'Jouw shake, zonder poeder. Maandagavond blenden, in een fles, mee naar de gym. Drinkbaar, dus je krijgt het binnen terwijl je nog aan het afkoelen bent. 36 gram eiwit uit echte kwark — meer dan de meeste wheyshakes. De banaan levert de snelle koolhydraten, en dát is na een nuchtere sessie het meest tijdgevoelige deel.', '36 g eiwit, drinkbaar — jouw shake zonder poeder.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('b04', 'Kwarkbak met havermout', '400 g magere kwark met havermout, banaan en wat walnoot.', array['BREAK_FAST']::text[], 'cold', 'portable', 'fast', true, 4, 'kwark', 'Extra koolhydraten via havermout. Dit is je lunch ná een nuchtere krachttraining: je spierglycogeen is leeg en dit is precies het moment waarop koolhydraten het best worden opgenomen.', '48 g eiwit plus havermout — voor na de nuchtere training.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('b05', 'De eiwit-boterham', 'Drie sneetjes volkoren met hüttenkäse, gekookte eieren en pindakaas.', array['BREAK_FAST']::text[], 'cold', 'portable', 'medium', false, 8, 'bread', 'Brood mag, maar je betaalt ervoor: 38 gram eiwit voor 572 kcal, tegen 44 gram voor 452 kcal bij de kwarkbak. Prima een of twee keer per week als je zin hebt in brood — niet als dagelijkse standaard. Let op: maximaal één sneetje met pindakaas, afgestreken lepel.', '38 g eiwit voor 572 kcal — brood mag, maar het kost wat.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('b06', 'Tonijnboterham', 'Drie sneetjes volkoren met tonijn, hüttenkäse, augurk en tomaat.', array['BREAK_FAST']::text[], 'cold', 'portable', 'medium', false, 6, 'bread', '38 gram eiwit uit een blik tonijn en drie sneetjes volkoren, voor bijna 200 kcal minder dan de eiwit-boterham — tonijn op water is vrijwel vetvrij. De augurk en tomaat houden het fris zonder iets te kosten. Goed mee te nemen naar kantoor.', '38 g eiwit voor 379 kcal — de magerste boterham.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('b07', 'Skyr met granola en aardbeien', '400 g skyr met een handje granola en verse aardbeien.', array['BREAK_FAST']::text[], 'cold', 'portable', 'medium', true, 3, 'skyr', 'Skyr zit qua eiwit nog boven kwark: 11 gram per 100. De granola is hier de traktatie — 30 gram levert 135 kcal, dus niet bijstrooien. Met de aardbeien kom je op 48 gram eiwit voor zo''n 435 kcal.', '48 g eiwit voor 435 kcal — de granola is de traktatie.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('b08', 'Hüttenkäse-crackers met gerookte zalm', 'Vier volkoren crackers met hüttenkäse en gerookte zalm.', array['BREAK_FAST']::text[], 'cold', 'portable', 'medium', false, 5, 'huttenkase', 'Gerookte zalm brengt vet mee (10 gram per 100), dus de portie blijft bewust bescheiden; de hüttenkäse doet het eiwitwerk. Samen 40 gram eiwit voor zo''n 445 kcal, en in vijf minuten op de crackers gelegd.', '40 g eiwit voor 447 kcal, in vijf minuten.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('b09', 'Kipsalade met edamame', 'Kipfilet en edamame op een bak rauwkost, met cashews en olijfolie.', array['BREAK_FAST']::text[], 'cold', 'portable', 'medium', false, 10, 'veg', 'Een lunch zonder zuivel of brood: kip en edamame samen goed voor zo''n 49 gram eiwit. Edamame levert als een van de weinige peulvruchten serieus eiwit én vezels. De cashews gaan van je notenbudget af — 10 gram, bewust bescheiden.', '49 g eiwit zonder zuivel of brood.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('b10', 'Eiersalade-boterham', 'Drie sneetjes volkoren met eiersalade van gekookt ei en hüttenkäse.', array['BREAK_FAST']::text[], 'cold', 'portable', 'medium', false, 8, 'egg', 'Drie eieren leveren 19 gram eiwit maar ook 15 gram vet; de hüttenkäse trekt het totaal naar 38 gram zonder veel calorieën toe te voegen. Kies deze als je zin hebt in brood en de kwarkbak je de neus uit komt.', '38 g eiwit — brooddag zonder pindakaas.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('b11', 'Kipfilet-wrap', 'Volkoren wrap met kipfilet, hummus, sla en tomaat.', array['BREAK_FAST']::text[], 'cold', 'on_the_go', 'medium', false, 7, 'bread', 'Meeneembaar zonder koelkastmoment: wrap, kip, hummus. 47 gram eiwit voor zo''n 440 kcal. De hummus vervangt boter en houdt de boel bij elkaar — 40 gram is de maat.', '47 g eiwit voor 439 kcal, eet uit de hand.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('b12', 'Griekse yoghurt met noten en honing', '400 g Griekse yoghurt 0% met walnoten en een theelepel honing.', array['BREAK_FAST']::text[], 'cold', 'portable', 'medium', true, 2, 'yoghurt', 'Griekse yoghurt 0% is qua cijfers vrijwel kwark: 10 gram eiwit per 100 voor 59 kcal. De walnoten zijn je omega-3-basis en gaan van het notenbudget af; de honing is één theelepel — meer wordt vloeibare suiker.', '43 g eiwit voor 388 kcal, klaar in twee minuten.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('s01', 'Kwark met blauwe bessen', '250 g magere kwark met 100 g blauwe bessen.', array['SNACK']::text[], 'cold', 'portable', 'medium', true, 2, 'kwark', '26 gram eiwit voor 192 kcal, en de bessen brengen vezels en iets zoets mee. De standaardsnack waar de rest van deze lijst aan wordt afgemeten.', '26 g eiwit voor 192 kcal — de standaardsnack.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('s02', 'Tonijn met rijstwafels', 'Een blik tonijn op water met drie rijstwafels.', array['SNACK']::text[], 'cold', 'portable', 'fast', false, 3, 'fish', 'Mager en snel verteerbaar: 26 gram eiwit voor 172 kcal, vrijwel zonder vet of vezels. Daarom ook geschikt vlak vóór inspanning — het ligt niet op je maag.', '26 g eiwit, bijna geen vet — ligt niet op je maag.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('s03', 'Hüttenkäse met tomaat en peper', '200 g hüttenkäse met tomaat en flink wat zwarte peper.', array['SNACK']::text[], 'cold', 'portable', 'medium', true, 2, 'huttenkase', 'Hüttenkäse is iets vetter dan kwark (4 gram per 100) maar je eet het hartig, met een vork — dat telt als variatie. 25 gram eiwit voor zo''n 200 kcal.', '25 g eiwit, hartig in plaats van zoet.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('s04', 'Gekookte eieren met cherrytomaatjes', 'Drie gekookte eieren met een hand cherrytomaatjes.', array['SNACK']::text[], 'cold', 'portable', 'medium', false, 2, 'egg', 'Drie eieren zijn 19 gram eiwit, maar ook 15 gram vet — daarom is dit een snack en geen dagelijkse standaard. Kook ze op zondag, dan liggen ze drie dagen klaar.', '20 g eiwit — kook ze op zondag voor drie dagen.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('s05', 'Skyr met kaneel', '300 g skyr met kaneel.', array['SNACK']::text[], 'cold', 'portable', 'fast', true, 1, 'skyr', '33 gram eiwit voor 189 kcal — de hoogste eiwitdichtheid van je snacklijst. Skyr is dikker dan kwark, dus het eet als iets. De kaneel kost niets.', '33 g eiwit voor 189 kcal — de dichtste eiwitsnack.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('s06', 'Kipfilet met komkommer en hummus', 'Plakjes kipfilet met komkommer en 40 g hummus om te dippen.', array['SNACK']::text[], 'cold', 'portable', 'medium', false, 4, 'meat', 'Kipfilet met komkommer en hummus: 29 gram eiwit voor zo''n 210 kcal. De hummus is de smaakmaker én het vet — 40 gram is de maat, het is geen dipbak.', '29 g eiwit voor 210 kcal.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('s07', 'Edamame', '150 g gedopte edamame met wat zout.', array['SNACK']::text[], 'cold', 'portable', 'medium', false, 5, 'veg', 'Het enige volledig plantaardige eiwitmoment in de lijst: 18 gram eiwit plus 7,5 gram vezels uit één kom edamame. Diepvries, vijf minuten, klaar.', '18 g plantaardig eiwit plus 7,5 g vezels.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('s08', 'Kwark-kefir drink', '250 g kwark losgeroerd met 100 ml kefir, drinkbaar.', array['SNACK']::text[], 'cold', 'on_the_go', 'fast', true, 2, 'smoothie', 'Drinkbare kwark: 28 gram eiwit voor 185 kcal, weg in twee minuten. Handig op dagen dat een bakje met een lepel te veel gedoe is — maar drink hem rustig, hij verzadigt minder dan dezelfde kwark met een lepel.', '28 g eiwit, drinkbaar in twee minuten.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('s09', 'Rijstwafels met hüttenkäse en gerookte zalm', 'Twee rijstwafels belegd met hüttenkäse en gerookte zalm.', array['SNACK']::text[], 'cold', 'portable', 'medium', false, 4, 'fish', 'Gerookte zalm op hüttenkäse: 26 gram eiwit voor zo''n 260 kcal. De zalm brengt het vet, de wafels het knapperige. Meer wafels toevoegen schiet niet op — het eiwit zit in de rest.', '26 g eiwit voor 257 kcal.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('s10', 'Griekse yoghurt met walnoot', '300 g Griekse yoghurt 0% met 10 g walnoot.', array['SNACK']::text[], 'cold', 'portable', 'medium', true, 2, 'yoghurt', '32 gram eiwit voor 242 kcal. De 10 gram walnoot gaat van je notenbudget af; op een rustdag houd je dan nog 20 gram over voor de rest van de dag.', '32 g eiwit; de walnoot gaat van je notenbudget af.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('s11', 'Pistachenoten in dop met skyr', '20 g pistachenoten in de dop, met 250 g skyr.', array['SNACK']::text[], 'cold', 'portable', 'medium', true, 3, 'skyr', 'Pistachenoten met dop dwingen je af te remmen: je moet ze pellen, dus je eet langzamer, en de doppen zijn een zichtbare teller. De skyr doet het eiwitwerk. Let op je notenbudget — deze 20 gram gaat eraf.', '32 g eiwit; de doppen zijn je ingebouwde teller.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('s12', 'Kipfilet met rauwkost', '150 g kipfilet met een bak rauwkost.', array['SNACK']::text[], 'cold', 'portable', 'medium', false, 4, 'meat', 'De zwaarste eiwitsnack in de lijst: 48 gram voor zo''n 270 kcal. Kies deze op dagen dat je bij lunch of diner tekortkomt — het is bijna een halve maaltijd.', '48 g eiwit — bijna een halve maaltijd.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('d01', 'Zalmfilet met zoete aardappel en broccoli', 'Gebakken zalmfilet met gekookte zoete aardappel en broccoli.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 25, 'fish', 'Zalm is je vette vis van de week: 36 gram eiwit plus de omega-3 die je uit noten niet haalt (EPA/DHA in plaats van ALA). De zoete aardappel vult je glycogeen aan, de broccoli doet de vezels. Rond de 620 kcal — een volwaardige herstelmaaltijd.', '46 g eiwit plus je omega-3 van de week.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('d02', 'Kipfilet met rijst en roergebakken groenten', 'Kipfilet met rijst en roergebakken paprika en ui.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 20, 'meat', 'Het werkpaard: 62 gram eiwit voor zo''n 620 kcal. Kip met rijst is de makkelijkste manier om je grootste eiwitmoment te halen zonder over je calorieband te gaan.', '62 g eiwit voor 621 kcal — het werkpaard.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('d03', 'Bolognese van mager gehakt met volkoren pasta', 'Tomatensaus met 5%-gehakt op volkoren pasta.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 30, 'meat', 'Mager gehakt (5%) scheelt tegenover gewoon gehakt zo''n 10 gram vet per 100. Met volkoren pasta kom je op 55 gram eiwit en ruim 10 gram vezels. Maak dubbele saus — die is morgen beter.', '55 g eiwit en ruim 10 g vezels.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('d04', 'Kabeljauw met aardappel en spinazie', 'Gestoomde kabeljauw met gekookte aardappelen en spinazie.', array['DINNER']::text[], 'warm', 'home_only', 'medium', false, 25, 'fish', 'De lichtste van je diners: 50 gram eiwit voor zo''n 490 kcal. Kabeljauw is vrijwel vetvrij, dus dit is de keuze op dagen dat lunch of snack al zwaar uitvielen.', '50 g eiwit voor maar 488 kcal — het lichtste diner.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('d05', 'Kalkoen-stirfry met paprika en rijst', 'Reepjes kalkoenfilet gewokt met paprika, geserveerd met rijst.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 20, 'meat', 'Kalkoenfilet is nog magerder dan kip: 29 gram eiwit per 100 voor 135 kcal. Met rijst en paprika een snelle wok van zo''n 590 kcal en 62 gram eiwit.', '62 g eiwit uit het magerste vlees dat je hebt.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('d06', 'Linzencurry met kip', 'Curry van linzen en kipfilet in lichte kokosmelk, met tomaat.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 30, 'meat', 'Linzen plus kip: dierlijk en plantaardig eiwit in één pan, samen 61 gram, plus de vezels die in de rest van je dag schaars zijn. De lichte kokosmelk houdt de curry binnen de band — de gewone verdubbelt het vet.', '61 g eiwit, dierlijk én plantaardig in één pan.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('d07', 'Biefstuk met aardappel en sperziebonen', 'Mager gebakken biefstuk met gekookte aardappelen en sperziebonen.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 25, 'meat', 'Magere biefstuk: 51 gram eiwit en goed opneembaar ijzer en B12. Rond de 620 kcal met aardappel en sperziebonen. Geen saus nodig.', '60 g eiwit plus ijzer en B12.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('d08', 'Garnalen-roerbak met noedels', 'Garnalen gewokt met paprika en noedels.', array['DINNER']::text[], 'warm', 'home_only', 'medium', false, 15, 'fish', 'Garnalen zijn extreem mager: 24 gram eiwit per 100 voor 99 kcal. Met noedels en paprika een roerbak van zo''n 525 kcal en 53 gram eiwit, in een kwartier op tafel.', '53 g eiwit, in een kwartier op tafel.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('d09', 'Grote omelet met kip en groente', 'Omelet van vier eieren, gevuld met kipfilet, paprika en tomaat.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 15, 'egg', 'Vier eieren leveren 25 gram eiwit maar ook het vet; de kip erin trekt het totaal naar 58 gram zonder veel extra calorieën. De omelet voor dagen dat er "niets in huis" is — eieren zijn er altijd.', '58 g eiwit — voor als er "niets in huis" is.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('d10', 'Tofu-teriyaki met rijst en edamame', 'Gebakken tofu in teriyakisaus met rijst en edamame.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 20, 'veg', 'Het vegetarische diner: tofu en edamame samen 39 gram eiwit — minder dan je andere diners, dus plan er een zwaardere snack naast. Tofu neemt de teriyaki op als een spons; meer saus is niet nodig.', '39 g eiwit, vegetarisch — plan een stevige snack ernaast.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('d11', 'Magere gehaktballen met aardappelpuree en groente', 'Gehaktballen van 5%-gehakt, puree van aardappel met melk, sperziebonen.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 30, 'meat', 'Gehaktballen van 5%-gehakt, puree van echte aardappel met melk in plaats van boter. Rond de 590 kcal en 53 gram eiwit — het comfortdiner dat binnen de calorieband blijft.', '53 g eiwit — comfortfood binnen de band.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('d12', 'Vis-traybake met zoete aardappel', 'Kabeljauw, zoete aardappel, paprika en ui van één bakplaat.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 35, 'fish', 'Alles op één bakplaat: witvis, zoete aardappel, paprika, olijfolie eroverheen en 25 minuten oven. Zo''n 540 kcal en 46 gram eiwit, en maar één ding om af te wassen.', '46 g eiwit, één bakplaat, één afwas.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('c01', 'Kwark met kaneel', '400 g magere kwark met kaneel.', array['CLOSE']::text[], 'cold', 'home_only', 'slow', true, 1, 'kwark', '40 gram caseïne voor 221 kcal — precies waar dit moment voor bestaat. Langzaam eiwit dat de komende 17 uur vasten overbrugt. De kaneel maakt het af zonder iets te kosten.', '40 g caseïne voor 221 kcal — de standaardafsluiter.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('c02', 'Kwark met blauwe bessen', '400 g magere kwark met 100 g blauwe bessen.', array['CLOSE']::text[], 'cold', 'home_only', 'slow', true, 2, 'kwark', 'Dezelfde 40 gram caseïne, plus 57 kcal aan bessen voor wie de kale kwark beu is. De vezels van de bessen zijn zo laat op de dag mooi meegenomen.', '41 g caseïne, plus bessen tegen de verveling.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('c03', 'Kwark met walnoot', '350 g magere kwark met 10 g walnoot.', array['CLOSE']::text[], 'cold', 'home_only', 'slow', true, 2, 'kwark', 'Iets minder kwark, 10 gram walnoot erbij — goed als je notenbudget nog ruimte heeft. Vet vertraagt de vertering, en vlak voor 17 uur vasten is dat hier juist een voordeel.', '37 g caseïne; de walnoot vertraagt — hier een voordeel.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('c04', 'Skyr naturel', '400 g skyr naturel.', array['CLOSE']::text[], 'cold', 'home_only', 'medium', true, 1, 'skyr', 'Skyr is net als kwark caseïnedominant, maar dikker en met 44 gram eiwit per 400 gram zelfs iets rijker. Voor wie kwark als afsluiter beu is: hetzelfde werk in een andere jas.', '44 g caseïnedominant eiwit — kwark in een andere jas.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('c05', 'Kwark-kefir drink', '300 g kwark losgeroerd met 100 ml kefir, drinkbaar.', array['CLOSE']::text[], 'cold', 'home_only', 'fast', true, 2, 'smoothie', 'De drinkbare afsluiter: 33 gram caseïne, weg in een minuut. Iets minder eiwit dan de bakjes — kies hem op dagen dat je dagtotaal al goed zit.', '33 g caseïne, drinkbaar — voor als het totaal al goed zit.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('c06', 'Kwark met honing en kaneel', '400 g magere kwark met een theelepel honing en kaneel.', array['CLOSE']::text[], 'cold', 'home_only', 'slow', true, 1, 'kwark', 'Een theelepel honing (21 kcal) maakt 400 gram kwark opeens een toetje. De goedkoopste truc in deze lijst: 40 gram caseïne die je met plezier eet.', '40 g caseïne die als een toetje eet.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('c07', 'Griekse yoghurt met vanille', '400 g Griekse yoghurt 0% met vanille-extract.', array['CLOSE']::text[], 'cold', 'home_only', 'medium', true, 1, 'yoghurt', 'Griekse yoghurt 0% met vanille: 40 gram caseïnedominant eiwit voor 241 kcal. Vanille-extract, geen vanillesuiker — dat scheelt niets qua smaak en alles qua suiker.', '40 g caseïnedominant eiwit voor 241 kcal.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('c08', 'Hüttenkäse met peper', '300 g hüttenkäse met zwarte peper.', array['CLOSE']::text[], 'cold', 'home_only', 'medium', true, 1, 'huttenkase', 'Hüttenkäse is óók caseïne: 36 gram voor 285 kcal. Iets vetter dan kwark, maar hartig in plaats van zoet — voor de avonden dat je geen zoete zuivel meer kunt zien.', '36 g caseïne, hartig — voor wie geen zoet meer wil.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('c09', 'Kwark met kaneel en cacao', '400 g magere kwark met kaneel en pure cacaopoeder.', array['CLOSE']::text[], 'cold', 'home_only', 'slow', true, 2, 'kwark', 'Cacao — de pure poeder, geen chocolademelk — maakt er een chocolade-toetje van voor 17 kcal extra. Nog steeds 41 gram caseïne.', '41 g caseïne als chocolade-toetje, 17 kcal extra.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('c10', 'Kwark met geraspte appel en kaneel', '400 g magere kwark met een halve geraspte appel en kaneel.', array['CLOSE']::text[], 'cold', 'home_only', 'slow', true, 3, 'kwark', 'Geraspte appel met kaneel is de appeltaart-versie: 40 gram caseïne voor zo''n 260 kcal. Rasp de appel vers, anders wordt hij bruin en jij ontevreden.', '40 g caseïne in de appeltaart-versie.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x01', 'Skyr-banaan-honing shake', 'Skyr, banaan, melk en honing, geblend tot een shake.', array['BREAK_FAST']::text[], 'cold', 'on_the_go', 'fast', true, 4, 'smoothie', 'Je nuchtere-trainingsshake zonder kwark: 43 gram eiwit uit skyr, drinkbaar in de auto naar kantoor. De banaan en honing zijn hier functioneel — na een lege training wil je juist snelle koolhydraten, en vet zit er amper in (3 gram).', '43 g eiwit, drinkbaar, 3 g vet.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x02', 'Aardbei-kwarkshake', 'Kwark, aardbeien, melk en honing, geblend tot een shake.', array['BREAK_FAST']::text[], 'cold', 'on_the_go', 'fast', true, 4, 'smoothie', 'Aardbeien maken kwark drinkbaar zonder veel calorieën: 45 gram eiwit voor zo''n 340 kcal en nog geen 3 gram vet. Blend hem de avond ervoor — na een nuchtere sessie wil je niet nog staan snijden.', '45 g eiwit voor 340 kcal, drinkbaar.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x03', 'Tonijn-rijstwafelbox', 'Anderhalf blik tonijn met vijf rijstwafels en augurk.', array['BREAK_FAST']::text[], 'cold', 'portable', 'fast', false, 5, 'fish', 'Blik tonijn en rijstwafels overleven een sporttas: 39 gram eiwit en nog geen 2 gram vet, dus je maag is er snel vanaf. De rijstwafels zijn hier de snelle koolhydraten, geen dieetgimmick.', '39 g eiwit, 2 g vet — overleeft elke sporttas.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x04', 'Garnalen-rijstbowl', 'Garnalen op witte rijst met komkommer, koud te eten.', array['BREAK_FAST']::text[], 'cold', 'portable', 'fast', false, 8, 'fish', 'Garnalen met witte rijst: 42 gram eiwit en ruim 40 gram snelle koolhydraten voor je lege spierglycogeen, met net 1 gram vet. Koud uit de meal-prep-bak prima te eten.', '42 g eiwit en 40+ g snelle koolhydraten, 1 g vet.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x05', 'Kipfilet-rijstbowl', 'Kipfilet op rijst met paprika en een lepel teriyaki, koud te eten.', array['BREAK_FAST']::text[], 'cold', 'portable', 'fast', false, 8, 'meat', 'Meal-prep-klassieker, koud te eten: 47 gram eiwit, en de rijst vult aan wat de training opmaakte. Mager (5 gram vet), dus snel je maag uit en je spieren in.', '47 g eiwit, 5 g vet — meal-prep-klassieker.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x06', 'Kalkoen-rijstwafelbox', 'Kalkoenfilet met vier rijstwafels en tomaat.', array['BREAK_FAST']::text[], 'cold', 'portable', 'fast', false, 5, 'meat', 'Kalkoen is de magerste vleesoptie die je hebt (1,5 gram vet per 100): 46 gram eiwit voor zo''n 320 kcal. Rijstwafels in plaats van brood houden vet en vezels laag — precies wat je na een nuchtere sessie wilt.', '46 g eiwit voor 320 kcal, bijna vetvrij.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x07', 'Skyr-bowl met banaan en honing', '400 g skyr met banaan en een theelepel honing.', array['BREAK_FAST']::text[], 'cold', 'portable', 'fast', true, 3, 'skyr', 'De lepelversie van de trainingsshake: 45 gram eiwit uit skyr, banaan en honing voor de snelle koolhydraten, en amper 1 gram vet. Werkt ook als je blender nog vies is.', '45 g eiwit, 1 g vet — de lepelversie van de shake.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x08', 'Griekse yoghurt met banaan en honing', '400 g Griekse yoghurt 0% met banaan en een theelepel honing.', array['BREAK_FAST']::text[], 'cold', 'portable', 'fast', true, 3, 'yoghurt', 'Zelfde opzet als de skyr-bowl, andere smaak: 41 gram eiwit voor zo''n 360 kcal, vrijwel vetvrij. Yoghurt 0% is dunner dan skyr — sneller weg, en na een nuchtere training is dat geen nadeel.', '41 g eiwit voor 362 kcal, vrijwel vetvrij.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x09', 'Skyr met aardbeien en honing', '400 g skyr met aardbeien en een theelepel honing.', array['BREAK_FAST']::text[], 'cold', 'portable', 'fast', true, 3, 'skyr', 'Aardbeien in plaats van banaan: zo''n 60 kcal minder en iets minder koolhydraten. Kies de banaan-versie direct na kracht; deze mag ook op de lichtere dagen.', '45 g eiwit voor 321 kcal — de lichtere skyr-bowl.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x10', 'Skyr met banaan', '250 g skyr met een banaan.', array['SNACK']::text[], 'cold', 'portable', 'fast', true, 2, 'skyr', 'Skyr met banaan: 29 gram eiwit en snelle koolhydraten, samen zo''n 260 kcal met minder dan 1 gram vet. Licht genoeg om er 45 minuten later op te tillen.', '29 g eiwit plus snelle koolhydraten, <1 g vet.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x11', 'Rijstwafels met kipfilet', 'Drie rijstwafels met plakjes kipfilet.', array['SNACK']::text[], 'cold', 'portable', 'fast', false, 3, 'meat', 'Kip op rijstwafels: 27 gram eiwit, bijna geen vet of vezels — dit zit je niet in de weg in de sportschool. Ook koud gewoon goed.', '27 g eiwit, bijna geen vet of vezels.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x12', 'Garnalen-cocktailcup', 'Gekookte garnalen met komkommer.', array['SNACK']::text[], 'cold', 'portable', 'fast', false, 4, 'fish', 'Garnalen met komkommer: 29 gram eiwit voor maar 128 kcal, het lichtste eiwitmoment in de lijst. Voor dagen dat je calorieband knelt maar je eiwit nog moet.', '29 g eiwit voor maar 128 kcal — de lichtste optie.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x13', 'Yoghurtdrink met honing', 'Griekse yoghurt 0% losgeroerd met melk en honing, drinkbaar.', array['SNACK']::text[], 'cold', 'on_the_go', 'fast', true, 2, 'yoghurt', 'Drinkbaar en mager: 34 gram eiwit, en de honing levert de snelle suiker die je drie kwartier voor het tillen wilt. Geen vezels die in de weg zitten.', '34 g eiwit, drinkbaar, met snelle suiker voor het tillen.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x14', 'Banaan met kwarkdip', 'Een banaan met 200 g kwark als dip, snuf kaneel.', array['SNACK']::text[], 'cold', 'portable', 'fast', true, 2, 'kwark', 'De banaan is hier de hoofdact, de kwark de dip: 21 gram eiwit en snelle koolhydraten. De lichtste pre-workout-optie die toch iets substantieels biedt.', '21 g eiwit plus snelle koolhydraten — de lichte pre-workout.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x15', 'Kwark met honing', '250 g magere kwark met een theelepel honing.', array['SNACK']::text[], 'cold', 'portable', 'fast', true, 1, 'kwark', 'Kwark met een theelepel honing: 25 gram eiwit voor 165 kcal, vrijwel vetvrij. Simpeler wordt een pre-workout niet.', '25 g eiwit voor 165 kcal, vrijwel vetvrij.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x16', 'Skyr met aardbeien', '250 g skyr met 100 g aardbeien.', array['SNACK']::text[], 'cold', 'portable', 'fast', true, 2, 'skyr', 'Skyr met aardbeien: 28 gram eiwit voor 190 kcal, nauwelijks vet of vezels. Fris genoeg voor de zomer, licht genoeg voor de sportschool.', '28 g eiwit voor 190 kcal, licht en fris.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x17', 'Rijstwafels met kalkoenfilet', 'Twee rijstwafels met plakjes kalkoenfilet.', array['SNACK']::text[], 'cold', 'portable', 'fast', false, 3, 'meat', 'Kalkoen op rijstwafels: 30 gram eiwit voor 189 kcal met 2 gram vet. Magerder wordt vlees niet — en het verteert er ook naar.', '30 g eiwit voor 189 kcal, 2 g vet.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x20', 'Skyr met blauwe bessen', '350 g skyr met 100 g blauwe bessen.', array['CLOSE']::text[], 'cold', 'home_only', 'medium', true, 2, 'skyr', 'De skyr-variant van de bessen-afsluiter: 39 gram caseïnedominant eiwit voor 278 kcal. Voor de rotatie — tien keer per week kwark gaat vervelen.', '39 g caseïnedominant eiwit voor 278 kcal.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x21', 'Skyr met kaneel', '350 g skyr met kaneel.', array['CLOSE']::text[], 'cold', 'home_only', 'medium', true, 1, 'skyr', '350 gram skyr met kaneel: 39 gram caseïnedominant eiwit voor 225 kcal — na de kale kwark de magerste afsluiter die je hebt.', '39 g caseïnedominant eiwit voor 225 kcal.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x22', 'Griekse yoghurt met blauwe bessen', '350 g Griekse yoghurt 0% met 100 g blauwe bessen.', array['CLOSE']::text[], 'cold', 'home_only', 'medium', true, 2, 'yoghurt', 'De yoghurt-versie van kwark met bessen: 36 gram caseïnedominant eiwit voor 264 kcal. Yoghurt 0% is dunner dan kwark — sommige avonden is dat juist prettig.', '36 g caseïnedominant eiwit voor 264 kcal.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x23', 'Hüttenkäse met cherrytomaat', '275 g hüttenkäse met cherrytomaatjes en zwarte peper.', array['CLOSE']::text[], 'cold', 'home_only', 'medium', true, 2, 'huttenkase', 'De hartige afsluiter: hüttenkäse met cherrytomaten, 34 gram caseïne voor zo''n 280 kcal. Voor wie ''s avonds geen zoete zuivel meer kan zien.', '34 g caseïne, hartig — de tweede niet-zoete afsluiter.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x30', 'XL kwarkbak met havermout', '450 g kwark met 60 g havermout, banaan, walnoot en honing.', array['BREAK_FAST']::text[], 'cold', 'portable', 'fast', true, 5, 'kwark', 'De XL-versie van de havermout-kwarkbak, voor na een zware nuchtere sessie: 55 gram eiwit en ruim 65 gram koolhydraten voor zo''n 655 kcal. De extra havermout en honing zijn geen luxe — dit is de lunch die je calorieband op trainingsdagen haalbaar maakt.', '55 g eiwit voor 656 kcal — de grote trainingslunch.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x31', 'Dubbele kipfilet-wrap', 'Twee volkoren wraps met kipfilet, hummus, rauwkost en tomaat.', array['BREAK_FAST']::text[], 'cold', 'portable', 'medium', false, 10, 'bread', 'Twee wraps in plaats van één: 63 gram eiwit voor zo''n 670 kcal. Kies deze op dagen dat de teller om 13:00 al achterloopt — dit is een lunch die het gat in één keer dichttrekt.', '63 g eiwit voor 670 kcal — dicht het gat in één keer.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x33', 'Zalm-pastasalade XL', 'Volkoren pasta met zalmfilet, edamame, cherrytomaat en olijfolie.', array['DINNER']::text[], 'either', 'home_only', 'slow', false, 25, 'fish', 'Het grote diner: 67 gram eiwit en zo''n 970 kcal uit zalm, volkorenpasta en edamame. Op zware trainingsdagen is dit hoe je aan de 2200+ kcal komt zonder te snaaien; op rustdagen is hij te groot.', '67 g eiwit en 970 kcal — voor zware trainingsdagen.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x34', 'Kip-rijstschotel XL met olijfolie', 'Grote portie kipfilet met rijst, paprika, ui en olijfolie.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 25, 'meat', '78 gram eiwit en ruim 900 kcal — het grootste bord in de bibliotheek. De olijfolie is hier bewust: op een zware trainingsdag heb je die calorieën nodig, anders haal je de band niet.', '78 g eiwit en 905 kcal — het grootste bord.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x35', 'Gehakt-rijstschotel', 'Mager gehakt met rijst, tomaat, paprika en olijfolie uit één pan.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 25, 'meat', 'Gehakt met rijst: 63 gram eiwit voor zo''n 875 kcal. Eén pan, vier componenten, en het gat tussen 1800 en 2200 kcal is gedicht.', '63 g eiwit voor 874 kcal, uit één pan.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x36', 'Volkoren pasta met tonijn en olijfolie', 'Twee blikken tonijn door volkoren pasta met tomaat, ui en olijfolie.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 20, 'fish', 'Pantry-diner XL: twee blikken tonijn, volkorenpasta en een flinke scheut olijfolie — 69 gram eiwit voor zo''n 815 kcal. De olie is hier de calorieknop: 15 gram erbij of eraf is 130 kcal.', '69 g eiwit voor 817 kcal — het pantry-diner XL.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x37', 'Tofu-groentecurry met edamame', 'Curry van tofu en edamame in lichte kokosmelk, met rijst.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 25, 'veg', 'Het tweede vegetarische diner: tofu en edamame, samen 44 gram eiwit. Minder dan een vleesdiner, dus plan hem op een dag waar de rest van je eiwit al ruim zit.', '44 g plantaardig eiwit — het tweede veggie-diner.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x38', 'Eierschotel met hüttenkäse en tomaat', 'Vier eieren in tomaat-paprikasaus, afgemaakt met hüttenkäse.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 20, 'egg', 'Eieren en hüttenkäse uit één pan: 48 gram eiwit voor zo''n 590 kcal. Het diner voor als vis noch vlees in huis is — eieren en hüttenkäse zijn er altijd.', '48 g eiwit — het eierdiner zonder vlees of vis.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x39', 'Kalkoen-omelet met spinazie', 'Omelet van drie eieren met kalkoenfilet, spinazie en tomaat.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 15, 'egg', 'Drie eieren plus kalkoenfilet: 49 gram eiwit voor zo''n 490 kcal. Lichter dan de eierschotel, dus handig op dagen waarop lunch en snack al zwaar waren — je haalt je eiwit zonder je calorieband te raken.', '49 g eiwit voor ~490 kcal — het lichte eierdiner.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x44', 'Linzen-dahl met edamame', 'Dahl van linzen en edamame in lichte kokosmelk, met rijst.', array['DINNER']::text[], 'warm', 'home_only', 'slow', false, 25, 'veg', 'Linzen en edamame samen: 41 gram plantaardig eiwit plus 14 gram vezels. Minder eiwit dan vlees of vis, dus plan hem op een dag waarop je zuivelmomenten het zware werk al doen — de vezels maken hem wel het meest verzadigende diner in de lijst.', '41 g plantaardig eiwit — het derde veggie-diner.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x40', 'Boterham met hüttenkäse en banaan', 'Twee sneetjes volkoren met hüttenkäse en plakjes banaan.', array['SNACK']::text[], 'cold', 'portable', 'medium', true, 4, 'bread', 'Een snack met brood erbij: 26 gram eiwit en zo''n 410 kcal. Bedoeld voor trainingsdagen waarop je aan het eind van de middag calorieën tekortkomt — niet voor rustdagen.', '26 g eiwit voor 412 kcal — de stevige trainingssnack.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x41', 'Wrap met kalkoen en hummus', 'Volkoren wrap met kalkoenfilet, hummus en rauwkost.', array['SNACK']::text[], 'cold', 'portable', 'medium', false, 5, 'bread', 'Wrap met kalkoen: 38 gram eiwit voor zo''n 370 kcal. De stevigste hartige snack in de lijst; op zware dagen is dit de oplossing, op rustdagen is een gewone snack genoeg.', '38 g eiwit voor 369 kcal — de stevigste hartige snack.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x42', 'Kwark met pecan (traktatie)', '250 g magere kwark met 15 g pecannoten.', array['SNACK']::text[], 'cold', 'portable', 'medium', true, 2, 'kwark', 'Dit is bewust een traktatie: pecan is de noot met de meeste calorieën en het minste eiwit — dessert dus, geen gezondheidskeuze. De 15 gram gaat gewoon van je notenbudget af; de kwark eronder doet het eigenlijke werk.', '26 g eiwit plus pecan — dit is dessert, geen gezondheidskeuze.')
insert into public.if_meals (code, name, description, eligible_slots, temperature, portability, digestion_speed, casein_dominant, prep_minutes, family, rationale, rationale_short) values ('x43', 'Skyr met drie paranoten', '200 g skyr met drie paranoten (15 g).', array['SNACK']::text[], 'cold', 'portable', 'medium', true, 2, 'skyr', 'Drie paranoten dekken je seleniumbehoefte ruim — en meer dan drie is echt af te raden, selenium kent een bovengrens. De skyr maakt er een volwaardig eiwitmoment van; de paranoten zijn hier het supplement.', '24 g eiwit plus je seleniumdosis — max drie noten.')
